<div class="card-dark"><h5><?= $item?'Editar':'Nuevo' ?> usuario</h5><form method="post" action="<?= url('usuarios/guardar') ?>" class="row g-2"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e($item['id']??'') ?>"><div class="col-md-3"><label>Nombre</label><input required class="form-control" name="nombre" value="<?= e($item['nombre']??'') ?>"></div><div class="col-md-3"><label>Apellido</label><input required class="form-control" name="apellido" value="<?= e($item['apellido']??'') ?>"></div><div class="col-md-3"><label>Usuario</label><input required class="form-control" name="usuario" value="<?= e($item['usuario']??'') ?>"></div><div class="col-md-3"><label>Email</label><input required type="email" class="form-control" name="email" value="<?= e($item['email']??'') ?>"></div><div class="col-md-3"><label>Teléfono</label><input class="form-control" name="telefono" value="<?= e($item['telefono']??'') ?>"></div><div class="col-md-3"><label>Cargo</label><input class="form-control" name="cargo" value="<?= e($item['cargo']??'') ?>"></div><div class="col-md-3"><label>Área</label><input class="form-control" name="area" value="<?= e($item['area']??'') ?>"></div><div class="col-md-3"><label>Rol</label><select required class="form-select" name="rol_id"><?php foreach($roles as $r): ?><option value="<?= $r['id'] ?>" <?= ($item['rol_id']??'')==$r['id']?'selected':'' ?>><?= e($r['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label>Estado</label><select class="form-select" name="estado"><?php foreach(['activo','inactivo'] as $e): ?><option <?= ($item['estado']??'activo')===$e?'selected':'' ?>><?= $e ?></option><?php endforeach; ?></select></div><div class="col-md-4"><label>Contraseña <?= $item?'(dejar en blanco para mantener)':'' ?></label><input class="form-control" type="password" name="password" <?= $item?'':'required' ?>></div><div class="col-12 d-flex gap-2 mt-3"><button class="btn btn-seim">Guardar usuario</button><a class="btn btn-outline-light" href="<?= url('usuarios') ?>">Cancelar</a></div></form></div>
